import { motion } from "framer-motion";
import { Link } from "react-router-dom";
import { ArrowUpRight } from "lucide-react";
import { COLLECTIONS } from "@/lib/collections";

// Asymmetric "tetris" grid spans (mobile = full width)
const SPANS = [
    "md:col-span-7 md:row-span-2 aspect-[4/5] md:aspect-auto",      // 0 navratri (big tall)
    "md:col-span-5 aspect-[4/5]",                                   // 1 mehendi
    "md:col-span-5 aspect-[4/5]",                                   // 2 wedding-guest
    "md:col-span-5 aspect-[4/5]",                                   // 3 couple
    "md:col-span-7 aspect-[5/4]",                                   // 4 brides-sister (big wide)
    "md:col-span-12 aspect-[16/9] md:aspect-[21/8]",                // 5 festive panoramic
];

function Card({ c, span, i }) {
    return (
        <motion.div
            initial={{ opacity: 0, y: 40 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true, amount: 0.2 }}
            transition={{ duration: 0.9, delay: i * 0.05, ease: [0.22, 0.61, 0.36, 1] }}
            className={`group relative overflow-hidden rounded-[2rem] md:rounded-[2.5rem] bg-cream ${span}`}
            data-testid={`collection-card-${c.slug}`}
        >
            <Link
                to={`/collection/${c.slug}`}
                className="absolute inset-0 z-30"
                aria-label={c.name}
                data-testid={`collection-link-${c.slug}`}
            />
            <img
                src={c.image}
                alt={c.name}
                loading="lazy"
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-[1.6s] ease-out group-hover:scale-[1.06]"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-espresso/75 via-espresso/15 to-transparent pointer-events-none" />

            <div className="pointer-events-none relative z-20 h-full w-full flex flex-col justify-end p-7 md:p-10 text-ivory">
                <div className="flex items-center gap-2 text-[10px] uppercase tracking-[0.3em] opacity-90 mb-2">
                    <span className="inline-block w-6 h-px bg-ivory/70" />
                    Collection / {String(i + 1).padStart(2, "0")}
                </div>
                <h3 className="font-serif text-3xl md:text-5xl leading-tight">
                    {c.name}
                </h3>
                <p className="serif-italic text-base md:text-lg text-ivory/85 mt-1">
                    {c.tagline}
                </p>

                <div className="mt-5 flex items-center justify-between">
                    <span className="text-[11px] uppercase tracking-[0.28em] text-ivory/80 group-hover:text-ivory transition-colors">
                        Explore collection
                    </span>
                    <span className="w-10 h-10 rounded-full border border-ivory/60 flex items-center justify-center group-hover:bg-ivory group-hover:text-espresso transition-all duration-500">
                        <ArrowUpRight className="w-4 h-4" strokeWidth={1.4} />
                    </span>
                </div>
            </div>
        </motion.div>
    );
}

export default function FeaturedCollections() {
    return (
        <section id="collections" data-testid="featured-collections" className="relative py-24 md:py-36 px-6 md:px-12 lg:px-20 bg-ivory">
            <div className="max-w-7xl mx-auto">
                <div className="grid grid-cols-12 gap-6 mb-14 md:mb-20">
                    <div className="col-span-12 md:col-span-7">
                        <p className="text-[11px] uppercase tracking-[0.32em] text-maroon mb-5">
                            The Launch Edit
                        </p>
                        <h2 className="font-serif text-4xl sm:text-5xl md:text-6xl text-espresso tracking-tightest leading-[1.04]">
                            Six chapters of <span className="serif-italic">cloth, colour</span>
                            <br className="hidden md:block" /> and ceremony.
                        </h2>
                    </div>
                    <div className="col-span-12 md:col-span-4 md:col-start-9 flex items-end">
                        <p className="text-base md:text-lg text-stone leading-relaxed">
                            Each capsule is a love letter to a moment — woven with India's
                            finest ateliers, ready to be unlocked at launch.
                        </p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-12 gap-5 md:gap-6">
                    {COLLECTIONS.map((c, i) => (
                        <Card key={c.slug} c={c} span={SPANS[i]} i={i} />
                    ))}
                </div>
            </div>
        </section>
    );
}
